      out.write("            chatBody.scrollTop = chatBody.scrollHeight;\n");
      out.write("        }, 500);\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // ===== SLIDER =====\n");
      out.write("    let currentSlide = 0;\n");
      out.write("    const slides = document.querySelectorAll('.slider-slide');\n");
      out.write("    const dots = document.querySelectorAll('.dot');\n");
      out.write("    const totalSlides = slides.length;\n");
      out.write("    let autoSlideInterval;\n");
      out.write("\n");
      out.write("    function updateSlider() {\n");
      out.write("        const track = document.getElementById('sliderTrack');\n");
      out.write("        track.style.transform = 'translateX(-' + (currentSlide * 100) + '%)';\n");
      out.write("        dots.forEach((dot, index) => {\n");
      out.write("            dot.classList.toggle('active', index === currentSlide);\n");
      out.write("        });\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    function changeSlide(direction) {\n");
      out.write("        currentSlide = (currentSlide + direction + totalSlides) % totalSlides;\n");
      out.write("        updateSlider();\n");
      out.write("        resetAutoSlide();\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    function goToSlide(index) {\n");
